class PostRow extends Component {
    public Post $post;

    #[On('post-updated')]
    public function refreshPost(): void {
        $this->post->refresh();
    }

    public function togglePublish(): void {
        $this->authorize('update', $this->post);
        $this->post->update(['status' => $this->post->isPublished() ? 'draft' : 'published']);
        $this->dispatch('post-updated');
    }

    public function delete(): void {
        $this->authorize('delete', $this->post);
        $this->post->delete();
        $this->dispatch('post-deleted');
    }
}

{{-- View --}}
<button wire:click='togglePublish'>Toggle</button>
<button wire:click='delete' wire:confirm='Are you sure?'>Delete</button>

