class PostListTest extends TestCase {
    use RefreshDatabase;

    public function test_shows_posts(): void {
        Post::factory()->count(3)->create();
        Livewire::test(PostList::class)
            ->assertViewHas('posts', fn($posts) => $posts->count() === 3);
    }
    public function test_search_filters_posts(): void {
        Post::factory()->create(['title' => 'PHP Guide']);
        Post::factory()->create(['title' => 'JS Guide']);
        Livewire::test(PostList::class)
            ->set('search', 'PHP')
            ->assertSee('PHP Guide')
            ->assertDontSee('JS Guide');
    }
    public function test_delete_removes_post(): void {
        $post = Post::factory()->create();
        Livewire::test(PostRow::class, ['post' => $post])
            ->call('delete')
            ->assertDispatched('post-deleted');
        $this->assertModelMissing($post);
    }
}

